#!/usr/bin/env python
"""
Bootstrap: Self-Assembly Engine
  - MonomerSpec with typed faces (capture/structural/linker/functional)
  - StackingEngine: pi-pi, H-bond, coordination, covalent scoring
  - AssemblyGrammar: valence+symmetry -> topology (chain/honeycomb/framework/cage)
  - MaterialPropertyPredictor: porosity, BET surface area, stability
  - Library monomers: urea tape, tripodal linker, MOF paddlewheel, pyrene stack
  - assembly_demand() for demand-driven design
  - 37 tests, 500 total, zero regression

Usage: python bootstrap_assembly_engine.py
"""
import base64, os, sys
if os.path.isfile("core/universal_schema.py"): root="."
elif os.path.isfile(os.path.join("..","core","universal_schema.py")): root=".."; os.chdir(root)
else: print("ERROR: Run from MABE root"); sys.exit(1)
FILES = {
    'core/assembly_engine.py': '',
    'tests/test_assembly_engine.py': '',
}

for path, b64 in FILES.items():
    os.makedirs(os.path.dirname(path), exist_ok=True)
    content = base64.b64decode(b64).decode("utf-8")
    with open(path, "w", encoding="utf-8") as f: f.write(content)
    print(f"  Wrote {path} ({len(content)} bytes)")
print("Done. Run: python -m pytest tests/test_assembly_engine.py -v")